/// <summary>Provides web search capabilities via DuckDuckGo HTML.</summary>
sealed class WebSearch(HttpClient httpClient)
{
    [Description(
        "Search the web for information. Returns a list of search result " +
        "titles, URLs, and snippets. Use different queries to explore " +
        "multiple aspects of a topic.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🌐 Searching: {query}");

        try
        {
            var encodedQuery = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encodedQuery}";
            var html = await httpClient.GetStringAsync(url, cancellationToken);

            var results = ParseSearchResults(html);
            if (results.Count == 0)
                return "No results found.";

            var sb = new StringBuilder();
            for (var i = 0; i < Math.Min(results.Count, 5); i++)
            {
                sb.AppendLine($"{i + 1}. {results[i].Title}");
                sb.AppendLine($"   URL: {results[i].Url}");
                sb.AppendLine($"   {results[i].Snippet}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description(
        "Fetch the text content of a web page. Use this to read detailed " +
        "information from a URL found in search results.")]
    public async Task<string> FetchPageAsync(
        [Description("The full URL of the page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  📄 Fetching: {url}");

        try
        {
            var html = await httpClient.GetStringAsync(url, cancellationToken);
            var text = StripHtml(html);

            const int maxLength = 4000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "\n\n[Content truncated...]";

            return text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseSearchResults(string html)
    {
        var results = new List<SearchResult>();

        var resultPattern = new Regex(
            @"<a[^>]+class=""result__a""[^>]*href=""([^""]*?)""[^>]*>(.*?)</a>" +
            @".*?<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);

        foreach (Match match in resultPattern.Matches(html))
        {
            var rawUrl = WebUtility.HtmlDecode(match.Groups[1].Value);

            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
            var uddgMatch = Regex.Match(rawUrl, @"[?&]uddg=([^&]+)");
            var actualUrl = uddgMatch.Success
                ? WebUtility.UrlDecode(uddgMatch.Groups[1].Value)
                : rawUrl;

            results.Add(new SearchResult(
                StripHtml(match.Groups[2].Value).Trim(),
                actualUrl,
                StripHtml(match.Groups[3].Value).Trim()));
        }

        return results;
    }

    private static string StripHtml(string html)
    {
        html = Regex.Replace(
            html, @"<(script|style)[^>]*>.*?</\1>", "",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);
        html = Regex.Replace(html, @"<[^>]+>", " ");
        html = WebUtility.HtmlDecode(html);
        html = Regex.Replace(html, @"\s+", " ");
        return html.Trim();
    }

    private record SearchResult(string Title, string Url, string Snippet);
}

/// <summary>In-memory note-taking tool for organizing research findings.</summary>
sealed class Notepad
{
    private readonly List<string> _notes = [];

    public int Count => _notes.Count;

    [Description(
        "Save a research note. Use this to record key findings, facts, " +
        "or insights discovered during research.")]
    public string AddNote(
        [Description("The note content to save")] string content)
    {
        _notes.Add(content);
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description(
        "Retrieve all saved research notes. Use this to review your " +
        "collected findings before writing the final summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"Note #{i + 1}:");
            sb.AppendLine(_notes[i]);
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

